let isTyping = false;
let currentTab = "dossier"; // Текущая вкладка

// Элементы DOM
const titleEl = document.getElementById("page-title");
const stampEl = document.getElementById("page-stamp");
const imgEl = document.getElementById("main-image");
const captionEl = document.getElementById("photo-caption");
const menuContainer = document.getElementById("menu-container");
const outputDiv = document.getElementById("terminal-output");
const tabs = document.querySelectorAll(".tab");

// 1. ФУНКЦИЯ ПЕРЕКЛЮЧЕНИЯ ВКЛАДОК
function switchTab(tabName) {
  if (isTyping) return; // Не переключаем во время печати

  currentTab = tabName;
  const data = archiveData[tabName];

  // Обновляем активный класс у вкладок
  tabs.forEach((t) => t.classList.remove("active"));
  // Находим нужную вкладку по тексту (упрощенно) или индексу, здесь проще через event, но сделаем перебор:
  // В данном случае просто обновим визуально, если бы у табов были ID, было бы проще.
  // Но мы можем найти таб по onclick атрибуту в HTML, но проще сделать так:
  const tabsArray = Array.from(tabs);
  if (tabName === "dossier") tabsArray[0].classList.add("active");
  if (tabName === "evidence") tabsArray[1].classList.add("active");
  if (tabName === "report") tabsArray[2].classList.add("active");

  // Меняем контент страницы
  titleEl.innerHTML = data.title;
  stampEl.innerText = data.stamp;
  imgEl.src = data.image;
  captionEl.innerText = data.caption;

  // Генерируем меню
  renderMenu(data.menu);

  // Очищаем терминал
  outputDiv.innerHTML = "<p>> ВЫБЕРИТЕ ПУНКТ МЕНЮ...</p>";
}

// 2. ГЕНЕРАЦИЯ МЕНЮ
function renderMenu(menuItems) {
  menuContainer.innerHTML = "";
  menuItems.forEach((item) => {
    const btn = document.createElement("button");
    btn.className = "menu-btn";
    btn.innerText = item.label;
    btn.onclick = () => loadContent(item.id);
    menuContainer.appendChild(btn);
  });
}

// 3. ПЕЧАТЬ ТЕКСТА
function loadContent(contentKey) {
  if (isTyping) return;
  isTyping = true;

  const outputDiv = document.getElementById("terminal-output");
  outputDiv.innerHTML = "";

  const lines = archiveData[currentTab].content[contentKey];
  let lineIndex = 0;

  function createLine() {
    if (lineIndex < lines.length) {
      const p = document.createElement("p");
      outputDiv.appendChild(p);

      // --- ИСПРАВЛЕНИЕ: Прокрутка вниз ---
      // Сразу прокручиваем к только что созданной пустой строке
      p.scrollIntoView({ behavior: "smooth", block: "end" });
      // -----------------------------------

      let charIndex = 0;
      const text = lines[lineIndex];

      function typeChar() {
        if (charIndex < text.length) {
          p.textContent += text.charAt(charIndex);
          charIndex++;
          setTimeout(typeChar, 20);
        } else {
          lineIndex++;
          setTimeout(createLine, 150);
        }
      }
      typeChar();
    } else {
      isTyping = false;
    }
  }
  createLine();
}

// ЗАПУСК ПРИ ЗАГРУЗКЕ
window.onload = () => {
  switchTab("dossier");
};
